   112→/** Compute how much a per-item discount deducts from a line's total */
   113→export function computeItemDiscountAmount(unitPrice: number, qty: number, discount?: LineItemDiscount): number {
   114→  if (!discount) return 0;
   115→  const lineTotal = unitPrice * qty;
   116→  if (discount.type === 'percent') return Math.min(lineTotal, lineTotal * discount.value / 100);
   117→  return Math.min(lineTotal, discount.value);
   118→}
   119→
   120→/** Sum of all per-item discount amounts */
   121→export function computeTotalItemDiscounts(items: any[], discounts: Record<string, LineItemDiscount>): number {
   122→  return items.reduce((sum, item) => {
   123→    const d = discounts[item.lineItemId];
   124→    return sum + computeItemDiscountAmount(computeUnitPrice(item), item.quantity, d);
   125→  }, 0);
   126→}
   127→
   128→/** Compute service charge amount */
   129→export function computeServiceChargeAmount(base: number, config?: ServiceCharge): number {
   130→  if (!config?.enabled) return 0;
   131→  if (config.type === 'fixed')   return Math.max(0, config.value);
   132→  if (config.type === 'percent') return Math.max(0, base * config.value / 100);
   133→  return 0;
   134→}
   135→
   136→/** Compute manual order discount amount */
   137→export function computeOrderDiscountAmount(base: number, discount?: OrderDiscount): number {
   138→  if (!discount) return 0;
   139→  if (discount.type === 'amount')  return Math.min(base, Math.max(0, discount.value));
   140→  if (discount.type === 'percent') return Math.min(base, base * Math.max(0, discount.value) / 100);
   141→  return 0;
   142→}
