   144→/**
   145→ * Compute full POS totals breakdown.
   146→ * All prices are tax-inclusive (VAT included in price).
   147→ */
   148→export function computePOSTotals(
   149→  items:          any[],
   150→  itemDiscounts:  Record<string, LineItemDiscount>,
   151→  pointsDiscount: number,
   152→  couponDiscount: number,
   153→  orderDiscount?: OrderDiscount,
   154→  serviceCharge?: ServiceCharge,
   155→): POSTotals {
   156→  // 1. Raw total (tax-inclusive)
   157→  const rawTotal = items.reduce((s, item) => s + computeUnitPrice(item) * item.quantity, 0);
   158→
   159→  // 2. Per-item discounts (applied first)
   160→  const itemDiscountAmt = computeTotalItemDiscounts(items, itemDiscounts);
   161→
   162→  // 3. After item discounts
   163→  const afterItemDiscounts = Math.max(0, rawTotal - itemDiscountAmt);
   164→
   165→  // 4. Points discount
   166→  const afterPoints = Math.max(0, afterItemDiscounts - pointsDiscount);
   167→
   168→  // 5. Coupon discount
   169→  const afterCoupon = Math.max(0, afterPoints - couponDiscount);
   170→
   171→  // 6. Manual order discount
   172→  const orderDiscountAmt = computeOrderDiscountAmount(afterCoupon, orderDiscount);
   173→  const afterOrderDiscount = Math.max(0, afterCoupon - orderDiscountAmt);
   174→
   175→  // 7. Service charge
   176→  const serviceChargeAmt = computeServiceChargeAmount(afterOrderDiscount, serviceCharge);
   177→
   178→  // 8. Grand total
   179→  const grandTotal = Math.max(0, afterOrderDiscount + serviceChargeAmt);
   180→
   181→  // 9. VAT breakdown (tax-inclusive: subtotal = grandTotal / 1.15)
   182→  const subtotal = grandTotal / (1 + VAT_RATE);
   183→  const tax      = grandTotal - subtotal;
   184→
   185→  return {
   186→    rawTotal,
   187→    subtotal,
   188→    tax,
   189→    itemDiscountAmt,
   190→    pointsDiscount,
   191→    couponDiscount,
   192→    orderDiscountAmt,
   193→    serviceChargeAmt,
   194→    grandTotal,
   195→    change: 0,
   196→  };
   197→}
