   230→/** Merge items from two carts — matching items (same product + size + addons) have their quantities summed */
   231→export function mergeCartItems(base: any[], incoming: any[]): any[] {
   232→  const result = [...base];
   233→  for (const inc of incoming) {
   234→    const addonKey = JSON.stringify(inc.customization?.selectedItemAddons || []);
   235→    const sizeKey  = inc.selectedSize || '';
   236→    const existing = result.find(b =>
   237→      b.coffeeItem.id === inc.coffeeItem.id &&
   238→      (b.selectedSize || '') === sizeKey &&
   239→      JSON.stringify(b.customization?.selectedItemAddons || []) === addonKey
   240→    );
   241→    if (existing) {
   242→      existing.quantity += inc.quantity;
   243→    } else {
   244→      result.push({ ...inc, lineItemId: newLineId() });
   245→    }
   246→  }
   247→  return result;
   248→}
