   250→/** Split cart items for N people — returns N arrays of items */
   251→export function splitCartByPersons(items: any[], persons: number): any[][] {
   252→  if (persons <= 1) return [items];
   253→  const result: any[][] = Array.from({ length: persons }, () => []);
   254→  items.forEach((item, i) => {
   255→    result[i % persons].push(item);
   256→  });
   257→  return result;
   258→}
   259→
   260→/** Calculate each person's share of the total */
   261→export function computePersonShares(total: number, persons: number): number[] {
   262→  if (persons <= 1) return [total];
   263→  const share = Math.floor((total / persons) * 100) / 100;
   264→  const shares = Array(persons).fill(share);
   265→  // Assign any rounding difference to the last person
   266→  shares[persons - 1] = Math.round((total - share * (persons - 1)) * 100) / 100;
   267→  return shares;
   268→}
