   271→export function computeComboDiscount(selectedItems: any[], comboPrice: number): number {
   272→  const fullPrice = selectedItems.reduce((s, i) => s + computeUnitPrice(i) * i.quantity, 0);
   273→  return Math.max(0, fullPrice - comboPrice);
   274→}
