   272→function generateTingWav(volume = 0.9, sampleRate = 22050): string {
   273→  const durationMs = 550;
   274→  const numSamples = Math.floor((sampleRate * durationMs) / 1000);
   275→  const buffer = new ArrayBuffer(44 + numSamples * 2);
   276→  const view = new DataView(buffer);
   277→  const write = (offset: number, str: string) => {
   278→    for (let i = 0; i < str.length; i++) view.setUint8(offset + i, str.charCodeAt(i));
   279→  };
   280→  write(0, 'RIFF');
   281→  view.setUint32(4, 36 + numSamples * 2, true);
   282→  write(8, 'WAVE');
   283→  write(12, 'fmt ');
   284→  view.setUint32(16, 16, true);
   285→  view.setUint16(20, 1, true);
   286→  view.setUint16(22, 1, true);
   287→  view.setUint32(24, sampleRate, true);
   288→  view.setUint32(28, sampleRate * 2, true);
   289→  view.setUint16(32, 2, true);
   290→  view.setUint16(34, 16, true);
   291→  write(36, 'data');
   292→  view.setUint32(40, numSamples * 2, true);
   293→
   294→  const partials = [
   295→    { freq: 1760, amp: 1.0 },
   296→    { freq: 3136, amp: 0.55 },
   297→    { freq: 4400, amp: 0.30 },
   298→    { freq: 6000, amp: 0.15 },
   299→  ];
   300→
   301→  for (let i = 0; i < numSamples; i++) {
   302→    const t = i / sampleRate;
   303→    const attack = Math.min(1, i / (sampleRate * 0.002));
   304→    const decay = Math.exp(-t * 6.5);
   305→    const env = attack * decay * volume;
   306→
   307→    let sample = 0;
   308→    for (const { freq, amp } of partials) {
   309→      sample += amp * Math.sin(2 * Math.PI * freq * t);
   310→    }
   311→    const totalAmp = partials.reduce((s, p) => s + p.amp, 0);
   312→    sample /= totalAmp;
   313→
   314→    view.setInt16(44 + i * 2, Math.round(sample * env * 29000), true);
   315→  }
   316→
   317→  const bytes = new Uint8Array(buffer);
   318→  let binary = '';
   319→  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
   320→  return 'data:audio/wav;base64,' + btoa(binary);
   321→}
