   414→function playBeepWebAudio(type: NotificationSoundType, volume: number): boolean {
   415→  try {
   416→    const ctx = getCtx();
   417→    if (!ctx || ctx.state !== 'running') return false;
   418→
   419→    const freqMap: Record<string, number[]> = {
   420→      cashierOrder: [660, 880],
   421→      success: [523, 659],
   422→      statusChange: [440],
   423→      alert: [880, 659],
   424→    };
   425→    const freqs = freqMap[type] || [523, 659, 784];
   426→    const master = ctx.createGain();
   427→    master.gain.value = volume;
   428→    master.connect(ctx.destination);
   429→
   430→    freqs.forEach((freq, i) => {
   431→      const osc = ctx.createOscillator();
   432→      const gain = ctx.createGain();
   433→      osc.connect(gain);
   434→      gain.connect(master);
   435→      osc.type = 'sine';
   436→      osc.frequency.value = freq;
   437→      const start = ctx.currentTime + i * 0.12;
   438→      gain.gain.setValueAtTime(0, start);
   439→      gain.gain.linearRampToValueAtTime(1 / freqs.length, start + 0.01);
   440→      gain.gain.exponentialRampToValueAtTime(0.001, start + 0.28);
   441→      osc.start(start);
   442→      osc.stop(start + 0.3);
   443→    });
   444→
   445→    audioUnlocked = true;
   446→    return true;
   447→  } catch {
   448→    return false;
   449→  }
   450→}
