   532→  if (isDuplicate(type)) return;
   533→  markPlayed(type);
   534→
   535→  // Always attempt to resume the AudioContext before playing.
   536→  // This handles the case where a browser suspends the context on a long-lived
   537→  // tab even after the keepalive heartbeat runs (e.g. tab was in background).
   538→  await ensureRunning();
