   540→  if (type === 'onlineOrderVoice') {
   541→    // Try the real MP4 alert first; fall back to synthetic bell if unavailable.
   542→    const mp4Played = await playMp4WithFallback(volume);
   543→    if (!mp4Played) {
   544→      await playTingAudio(volume);
   545→      await new Promise(r => setTimeout(r, 320));
   546→      await playTingAudio(volume);
   547→      await new Promise(r => setTimeout(r, 320));
   548→      await playTingAudio(volume * 0.85);
   549→    }
   550→  } else if (type === 'newOrder') {
