   554→    await playTingAudio(volume);
   555→    await new Promise(r => setTimeout(r, 320));
   556→    await playTingAudio(volume * 0.85);
   557→  } else if (type === 'cashierOrder') {
   558→    await playBeep('cashierOrder', volume);
   559→    await new Promise(r => setTimeout(r, 200));
   560→    await playBeep('cashierOrder', volume * 0.8);
   561→  } else {
   562→    await playBeep(type, volume);
   563→  }
   564→}
