    93→export async function updateOrderStatus(localId: string, status: OfflineOrder["status"], error?: string): Promise<void> {
    94→  const db = await openDB();
    95→  return new Promise((resolve, reject) => {
    96→    const tx = db.transaction(STORE_NAME, "readwrite");
    97→    const store = tx.objectStore(STORE_NAME);
    98→    const getReq = store.get(localId);
    99→    getReq.onsuccess = () => {
   100→      const record = getReq.result as OfflineOrder | undefined;
   101→      if (record) {
   102→        record.status = status;
   103→        if (error) record.error = error;
   104→        if (status === "pending") {
   105→          // Going back to pending means a retry — schedule next retry with backoff
   106→          const newCount = (record.retryCount || 0) + 1;
   107→          record.retryCount = newCount;
   108→          record.lastRetryAt = new Date().toISOString();
   109→          const delayMs = RETRY_DELAYS_MS[Math.min(newCount - 1, RETRY_DELAYS_MS.length - 1)];
   110→          record.nextRetryAt = new Date(Date.now() + delayMs).toISOString();
   111→          // Mark as failed permanently if max retries exceeded
   112→          if (newCount >= MAX_RETRIES) {
   113→            record.status = "failed";
   114→            record.error = error || `فشل بعد ${MAX_RETRIES} محاولات`;
   115→          }
   116→        }
   117→        store.put(record);
   118→      }
   119→      resolve();
   120→    };
   121→    getReq.onerror = () => reject(getReq.error);
   122→  });
   123→}
