     9→ *   useRealtimeEvent("new_order", (data) => setOrders(prev => [data.order, ...prev]));
    10→ *   useRealtimeEvent("order_updated", handleUpdate);
    11→ *
    12→ *   // Get connection status
    13→ *   const { connected, reconnectCount } = useRealtimeStatus();
    14→ *
    15→ *   // Send a message
    16→ *   const { send } = useRealtimeSend();
    17→ *   send("pos_cart_update", { payload: cart });
    18→ */
    19→
    20→import { useEffect, useRef, useState, useCallback } from "react";
    21→import { getRealtimeEngine } from "@/lib/realtime-engine";
    22→
    23→// ── Shared connection init ────────────────────────────────────────────────────
    24→
    25→let _initDone = false;
    26→
    27→function ensureConnected(subscribePayload?: object) {
    28→  if (_initDone) return;
    29→  _initDone = true;
    30→  const engine = getRealtimeEngine(subscribePayload);
    31→  if (!engine.connected) engine.connect(subscribePayload);
    32→}
    33→
    34→// ── useRealtimeEvent ──────────────────────────────────────────────────────────
    35→
    36→export function useRealtimeEvent<T = any>(
    37→  event:   string,
    38→  handler: (data: T) => void,
    39→  subscribePayload?: object
    40→) {
    41→  const handlerRef = useRef(handler);
    42→  handlerRef.current = handler;
    43→
    44→  useEffect(() => {
    45→    ensureConnected(subscribePayload);
    46→    const engine = getRealtimeEngine();
    47→    const off = engine.on(event, (data: T) => handlerRef.current(data));
    48→    return off;
    49→  }, [event]); // eslint-disable-line react-hooks/exhaustive-deps
    50→}
    51→
    52→// ── useRealtimeStatus ─────────────────────────────────────────────────────────
    53→
    54→interface RealtimeStatus {
    55→  connected:      boolean;
    56→  reconnectCount: number;
    57→}
    58→
    59→export function useRealtimeStatus(): RealtimeStatus {
    60→  const [status, setStatus] = useState<RealtimeStatus>({
    61→    connected:      false,
    62→    reconnectCount: 0,
    63→  });
    64→
    65→  useEffect(() => {
    66→    ensureConnected();
    67→    const engine = getRealtimeEngine();
    68→
    69→    const offConn = engine.on("_connected", () =>
    70→      setStatus(prev => ({ connected: true, reconnectCount: prev.reconnectCount }))
    71→    );
    72→    const offDisc = engine.on("_disconnected", () =>
    73→      setStatus(prev => ({ connected: false, reconnectCount: prev.reconnectCount + 1 }))
    74→    );
    75→
    76→    // Sync initial state
    77→    setStatus(prev => ({ ...prev, connected: engine.connected }));
    78→
    79→    return () => { offConn(); offDisc(); };
    80→  }, []);
    81→
    82→  return status;
    83→}
    84→
    85→// ── useRealtimeSend ───────────────────────────────────────────────────────────
    86→
    87→export function useRealtimeSend() {
    88→  const send = useCallback((type: string, data: Record<string, any> = {}, requireAck = false) => {
    89→    const engine = getRealtimeEngine();
    90→    return engine.send(type, data, requireAck);
    91→  }, []);
    92→
    93→  return { send };
    94→}
    95→
    96→// ── useRealtimeConnection ─────────────────────────────────────────────────────
    97→// All-in-one hook: connect + subscribe to multiple events
    98→
    99→interface RTEventMap {
   100→  [event: string]: (data: any) => void;
   101→}
   102→
   103→export function useRealtimeConnection(
   104→  subscribePayload: object,
   105→  eventHandlers:    RTEventMap
   106→) {
   107→  const handlersRef = useRef(eventHandlers);
   108→  handlersRef.current = eventHandlers;
   109→
   110→  useEffect(() => {
   111→    ensureConnected(subscribePayload);
   112→    const engine = getRealtimeEngine(subscribePayload);
   113→
   114→    const offs = Object.entries(handlersRef.current).map(([event, handler]) =>
   115→      engine.on(event, (data: any) => handlersRef.current[event]?.(data))
   116→    );
   117→
   118→    return () => offs.forEach(off => off());
   119→  }, []); // eslint-disable-line react-hooks/exhaustive-deps
   120→}
