     1→/**
     2→ * Real-time Engine — WebSocket with ACK + Event Queue + Reconnection
     3→ * ───────────────────────────────────────────────────────────────────
     4→ * • Message sequence numbers on both client and server
     5→ * • ACK system: auto-ack critical events (orders, notifications)
     6→ * • Event queue: buffers outgoing messages when offline, flushes on reconnect
     7→ * • Reconnection: exponential backoff (1s → 2s → 4s → ... → 30s) with jitter
     8→ * • State recovery: re-subscribe + request missed events on reconnect
     9→ * • Typed event system with wildcard support
    10→ */
    11→
    12→type RTEventType = string;
    13→type RTHandler   = (data: any) => void;
    14→
    15→interface OutboundMsg {
    16→  seq:       number;
    17→  type:      RTEventType;
    18→  data:      Record<string, any>;
    19→  timestamp: number;
    20→  acked:     boolean;
    21→}
    22→
    23→export interface RTOptions {
    24→  reconnectBaseMs?: number;
    25→  reconnectMaxMs?:  number;
    26→  ackTimeoutMs?:    number;
    27→  maxQueueSize?:    number;
    28→  heartbeatMs?:     number;
    29→}
    30→
    31→export class RealtimeEngine {
    32→  private ws:                WebSocket | null = null;
    33→  private handlers:          Map<RTEventType, Set<RTHandler>> = new Map();
    34→  private outQueue:          OutboundMsg[] = [];
    35→  private pendingAcks:       Map<number, ReturnType<typeof setTimeout>> = new Map();
    36→  private seq =              0;
    37→  private lastReceivedSeq =  0;
    38→  private reconnectAttempts = 0;
    39→  private reconnectTimer:    ReturnType<typeof setTimeout> | null = null;
    40→  private heartbeatTimer:    ReturnType<typeof setInterval> | null = null;
    41→  private subscribePayload:  object | null = null;
    42→  private isDestroyed =      false;
    43→  private opts:              Required<RTOptions>;
    44→
    45→  readonly url: string;
    46→
    47→  constructor(url: string, opts: RTOptions = {}) {
    48→    this.url  = url;
    49→    this.opts = {
    50→      reconnectBaseMs: opts.reconnectBaseMs ?? 1_000,
    51→      reconnectMaxMs:  opts.reconnectMaxMs  ?? 30_000,
    52→      ackTimeoutMs:    opts.ackTimeoutMs    ?? 8_000,
    53→      maxQueueSize:    opts.maxQueueSize    ?? 200,
    54→      heartbeatMs:     opts.heartbeatMs     ?? 25_000,
    55→    };
    56→  }
    57→
    58→  // ── Connection ────────────────────────────────────────────────────────────
    59→
    60→  connect(subscribePayload?: object) {
    61→    if (subscribePayload) this.subscribePayload = subscribePayload;
    62→    if (this.isDestroyed) return;
    63→    if (this.ws?.readyState === WebSocket.CONNECTING) return;
    64→
    65→    try {
    66→      this.ws           = new WebSocket(this.url);
    67→      this.ws.onopen    = this.onOpen;
    68→      this.ws.onclose   = this.onClose;
    69→      this.ws.onerror   = this.onError;
    70→      this.ws.onmessage = this.onMessage;
    71→    } catch (e) {
    72→      this.scheduleReconnect();
    73→    }
    74→  }
    75→
    76→  disconnect() {
    77→    this.isDestroyed = true;
    78→    this.clearTimers();
    79→    this.ws?.close(1000, 'client_disconnect');
    80→    this.ws = null;
    81→  }
    82→
    83→  get connected(): boolean {
    84→    return this.ws?.readyState === WebSocket.OPEN;
    85→  }
    86→
    87→  // ── Subscriptions ─────────────────────────────────────────────────────────
    88→
    89→  on(event: RTEventType, handler: RTHandler): () => void {
    90→    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    91→    this.handlers.get(event)!.add(handler);
    92→    return () => this.off(event, handler);
    93→  }
    94→
    95→  off(event: RTEventType, handler: RTHandler) {
    96→    this.handlers.get(event)?.delete(handler);
    97→  }
    98→
    99→  private emit(event: RTEventType, data: any) {
   100→    this.handlers.get(event)?.forEach(h => {
   101→      try { h(data); } catch (e) { console.error(`[RT] Handler error (${event}):`, e); }
   102→    });
   103→    if (event !== '*') {
   104→      this.handlers.get('*')?.forEach(h => {
   105→        try { h({ event, ...data }); } catch (_) {}
   106→      });
   107→    }
   108→  }
   109→
   110→  // ── Sending ───────────────────────────────────────────────────────────────
   111→
   112→  send(type: string, data: Record<string, any> = {}, requireAck = false): number {
   113→    const msg: OutboundMsg = {
   114→      seq:       ++this.seq,
   115→      type,
   116→      data,
   117→      timestamp: Date.now(),
   118→      acked:     !requireAck,
   119→    };
   120→
   121→    if (this.connected) {
   122→      this._write(msg);
   123→    } else if (this.outQueue.length < this.opts.maxQueueSize) {
   124→      this.outQueue.push(msg);
   125→    }
   126→
   127→    if (requireAck) this.waitForAck(msg);
