   129→  }
   130→
   131→  private _write(msg: OutboundMsg) {
   132→    if (!this.connected) { this.outQueue.unshift(msg); return; }
   133→    try {
   134→      this.ws!.send(JSON.stringify({ seq: msg.seq, type: msg.type, timestamp: msg.timestamp, ...msg.data }));
   135→    } catch (_) {
   136→      if (this.outQueue.length < this.opts.maxQueueSize) this.outQueue.unshift(msg);
   137→    }
   138→  }
   139→
   140→  private waitForAck(msg: OutboundMsg) {
   141→    const timer = setTimeout(() => {
   142→      this.pendingAcks.delete(msg.seq);
   143→      // Retry on ack timeout
   144→      if (!msg.acked && this.outQueue.length < this.opts.maxQueueSize) {
   145→        this.outQueue.push({ ...msg, seq: ++this.seq });
   146→      }
   147→    }, this.opts.ackTimeoutMs);
   148→    this.pendingAcks.set(msg.seq, timer);
   149→  }
