/**
 * POS Engine — Professional Restaurant POS Business Logic
 * ════════════════════════════════════════════════════════
 * Pure TypeScript — no React, no side effects.
 * All state types and calculation functions for the POS system.
 */

export type OrderType    = "dine_in" | "takeaway" | "delivery" | "car_pickup";
export type PaymentMethod = "cash" | "card" | "fuji-card" | "split";

export interface LineItemDiscount {
  type:  'percent' | 'amount';
  value: number;
}

export interface OrderDiscount {
  type:  'percent' | 'amount';
  value: number;
  reason?: string;
}

export interface ServiceCharge {
  enabled: boolean;
  type:    'percent' | 'fixed';
  value:   number;
}

export interface PersonPayment {
  id: string;
  method: 'cash' | 'card' | 'mixed';
  amount: string;
  cashAmount?: string;
  cardAmount?: string;
}

export interface CartSnapshot {
  id:            string;
  name:          string;
  orderItems:    any[];
  orderType:     OrderType;
  tableNumber:   string;
  customerName:  string;
  customerPhone: string;
  orderNote:     string;
  paymentMethod: PaymentMethod;
  splitCashAmount: string;
  personPayments: PersonPayment[];
  itemDiscounts: Record<string, LineItemDiscount>;
  orderDiscount?: OrderDiscount;
  serviceCharge?: ServiceCharge;
  createdAt:     number;
}

export interface HeldCart extends CartSnapshot {
  heldAt:      number;
  totalAmount: number;
}

export interface CartTab {
  id:        string;
  name:      string;
  itemCount: number;
  total:     number;
  createdAt: number;
}

export interface POSTotals {
  rawTotal:         number;
  subtotal:         number;
  tax:              number;
  itemDiscountAmt:  number;
  pointsDiscount:   number;
  couponDiscount:   number;
  orderDiscountAmt: number;
  serviceChargeAmt: number;
  grandTotal:       number;
  change:           number;
}

export const VAT_RATE = 0.15;

export function computeUnitPrice(item: any): number {
  let base = Number(item.coffeeItem?.price) || 0;
  if (item.selectedSize && item.coffeeItem?.availableSizes) {
    const size = item.coffeeItem.availableSizes.find((s: any) => s.nameAr === item.selectedSize);
    if (size) base = Number(size.price) || 0;
  }
  const addons = (item.customization?.selectedItemAddons || [])
    .reduce((s: number, a: any) => s + (Number(a.price) || 0), 0);
  return base + addons;
}

export function computeItemDiscountAmount(unitPrice: number, qty: number, discount?: LineItemDiscount): number {
  if (!discount) return 0;
  const lineTotal = unitPrice * qty;
  if (discount.type === 'percent') return Math.min(lineTotal, lineTotal * discount.value / 100);
  return Math.min(lineTotal, discount.value);
}

export function computeTotalItemDiscounts(items: any[], discounts: Record<string, LineItemDiscount>): number {
  return items.reduce((sum, item) => {
    const d = discounts[item.lineItemId];
    return sum + computeItemDiscountAmount(computeUnitPrice(item), item.quantity, d);
  }, 0);
}

export function computeServiceChargeAmount(base: number, config?: ServiceCharge): number {
  if (!config?.enabled) return 0;
  if (config.type === 'fixed')   return Math.max(0, config.value);
  if (config.type === 'percent') return Math.max(0, base * config.value / 100);
  return 0;
}

export function computeOrderDiscountAmount(base: number, discount?: OrderDiscount): number {
  if (!discount) return 0;
  if (discount.type === 'amount')  return Math.min(base, Math.max(0, discount.value));
  if (discount.type === 'percent') return Math.min(base, base * Math.max(0, discount.value) / 100);
  return 0;
}

export function computePOSTotals(
  items:          any[],
  itemDiscounts:  Record<string, LineItemDiscount>,
  pointsDiscount: number,
  couponDiscount: number,
  orderDiscount?: OrderDiscount,
  serviceCharge?: ServiceCharge,
): POSTotals {
  const rawTotal = items.reduce((s, item) => s + computeUnitPrice(item) * item.quantity, 0);
  const itemDiscountAmt = computeTotalItemDiscounts(items, itemDiscounts);
  const afterItemDiscounts = Math.max(0, rawTotal - itemDiscountAmt);
  const afterPoints = Math.max(0, afterItemDiscounts - pointsDiscount);
  const afterCoupon = Math.max(0, afterPoints - couponDiscount);
  const orderDiscountAmt = computeOrderDiscountAmount(afterCoupon, orderDiscount);
  const afterOrderDiscount = Math.max(0, afterCoupon - orderDiscountAmt);
  const serviceChargeAmt = computeServiceChargeAmount(afterOrderDiscount, serviceCharge);
  const grandTotal = Math.max(0, afterOrderDiscount + serviceChargeAmt);
  const subtotal = grandTotal / (1 + VAT_RATE);
  const tax      = grandTotal - subtotal;

  return {
    rawTotal, subtotal, tax,
    itemDiscountAmt, pointsDiscount, couponDiscount,
    orderDiscountAmt, serviceChargeAmt, grandTotal, change: 0,
  };
}

export function newCartId(): string {
  return `cart-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
}

export function newLineId(): string {
  return Math.random().toString(36).substr(2, 9);
}

export function blankCart(id: string, name: string): CartSnapshot {
  return {
    id, name,
    orderItems:      [],
    orderType:       'dine_in',
    tableNumber:     '',
    customerName:    '',
    customerPhone:   '',
    orderNote:       '',
    paymentMethod:   'cash',
    splitCashAmount: '',
    personPayments: [{ id: '1', method: 'cash' as const, amount: '' }],
    itemDiscounts:   {},
    createdAt:       Date.now(),
  };
}

export function mergeCartItems(base: any[], incoming: any[]): any[] {
  const result = [...base];
  for (const inc of incoming) {
    const addonKey = JSON.stringify(inc.customization?.selectedItemAddons || []);
    const sizeKey  = inc.selectedSize || '';
    const existing = result.find(b =>
      b.coffeeItem.id === inc.coffeeItem.id &&
      (b.selectedSize || '') === sizeKey &&
      JSON.stringify(b.customization?.selectedItemAddons || []) === addonKey
    );
    if (existing) {
      existing.quantity += inc.quantity;
    } else {
      result.push({ ...inc, lineItemId: newLineId() });
    }
  }
  return result;
}

export function splitCartByPersons(items: any[], persons: number): any[][] {
  if (persons <= 1) return [items];
  const result: any[][] = Array.from({ length: persons }, () => []);
  items.forEach((item, i) => { result[i % persons].push(item); });
  return result;
}

export function computePersonShares(total: number, persons: number): number[] {
  if (persons <= 1) return [total];
  const share = Math.floor((total / persons) * 100) / 100;
  const shares = Array(persons).fill(share);
  shares[persons - 1] = Math.round((total - share * (persons - 1)) * 100) / 100;
  return shares;
}

/**
 * Notification Sound System — Fuji Cafe
 */

export type NotificationSoundType =
  | 'newOrder'
  | 'onlineOrderVoice'
  | 'cashierOrder'
  | 'statusChange'
  | 'success'
  | 'alert';

export type SoundChannel = 'manual' | 'online' | 'car';

export interface ChannelSoundConfig {
  enabled: boolean;
  soundType: NotificationSoundType;
  volume: number;
}

const CHANNEL_SOUND_KEY = 'fuji_channel_sounds';

const CHANNEL_DEFAULTS: Record<SoundChannel, ChannelSoundConfig> = {
  manual:  { enabled: true, soundType: 'newOrder',         volume: 0.6 },
  online:  { enabled: true, soundType: 'onlineOrderVoice', volume: 1.0 },
  car:     { enabled: true, soundType: 'onlineOrderVoice', volume: 1.0 },
};

export function getChannelConfig(channel: SoundChannel): ChannelSoundConfig {
  try {
    const raw = localStorage.getItem(CHANNEL_SOUND_KEY);
    if (!raw) return { ...CHANNEL_DEFAULTS[channel] };
    const map = JSON.parse(raw) as Record<SoundChannel, ChannelSoundConfig>;
    return map[channel] ? { ...CHANNEL_DEFAULTS[channel], ...map[channel] } : { ...CHANNEL_DEFAULTS[channel] };
  } catch { return { ...CHANNEL_DEFAULTS[channel] }; }
}

export function setChannelConfig(channel: SoundChannel, config: Partial<ChannelSoundConfig>): void {
  try {
    const raw = localStorage.getItem(CHANNEL_SOUND_KEY);
    const map: Record<string, ChannelSoundConfig> = raw ? JSON.parse(raw) : {};
    map[channel] = { ...CHANNEL_DEFAULTS[channel], ...(map[channel] || {}), ...config };
    localStorage.setItem(CHANNEL_SOUND_KEY, JSON.stringify(map));
  } catch {}
}

export function getAllChannelConfigs(): Record<SoundChannel, ChannelSoundConfig> {
  return { manual: getChannelConfig('manual'), online: getChannelConfig('online'), car: getChannelConfig('car') };
}

export async function playChannelSound(channel: SoundChannel): Promise<void> {
  const cfg = getChannelConfig(channel);
  if (!cfg.enabled) return;
  await playNotificationSound(cfg.soundType, cfg.volume);
}

let sharedCtx: AudioContext | null = null;
let keepaliveTimer: ReturnType<typeof setInterval> | null = null;

function getCtx(): AudioContext | null {
  try {
    if (!sharedCtx || sharedCtx.state === 'closed') {
      sharedCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return sharedCtx;
  } catch { return null; }
}

async function ensureRunning(): Promise<boolean> {
  try {
    const ctx = getCtx();
    if (!ctx) return false;
    if (ctx.state === 'suspended') await ctx.resume();
    return ctx.state === 'running';
  } catch { return false; }
}

function playSilentPing(): void {
  try {
    const ctx = getCtx();
    if (!ctx || ctx.state !== 'running') return;
    const buf = ctx.createBuffer(1, 1, 22050);
    const src = ctx.createBufferSource();
    src.buffer = buf;
    src.connect(ctx.destination);
    src.start();
  } catch {}
}

function startKeepalive(): void {
  if (keepaliveTimer !== null) return;
  keepaliveTimer = setInterval(() => {
    if (!sharedCtx || sharedCtx.state === 'closed') {
      if (keepaliveTimer !== null) clearInterval(keepaliveTimer);
      keepaliveTimer = null;
      return;
    }
    if (sharedCtx.state === 'suspended') {
      sharedCtx.resume().then(() => playSilentPing()).catch(() => {});
    } else { playSilentPing(); }
  }, 25_000);
}

if (typeof window !== 'undefined') {
  const unlock = async () => {
    const running = await ensureRunning();
    if (running) { audioUnlocked = true; startKeepalive(); }
  };
  ['click', 'keydown', 'touchstart', 'mousedown', 'pointerdown'].forEach(evt =>
    document.addEventListener(evt, unlock, { capture: true, passive: true })
  );
}

let audioUnlocked = false;

export function isAudioUnlocked(): boolean {
  return audioUnlocked || (sharedCtx?.state === 'running');
}

export async function initAudioUnlock(): Promise<void> {
  try {
    const running = await ensureRunning();
    if (running) { audioUnlocked = true; startKeepalive(); }
  } catch {}
}

const SOUND_PREF_KEY = 'fuji_sound_enabled';

export function getSoundEnabled(pageKey = 'default'): boolean {
  try {
    const raw = localStorage.getItem(SOUND_PREF_KEY);
    if (!raw) return true;
    const map = JSON.parse(raw) as Record<string, boolean>;
    return map[pageKey] !== false;
  } catch { return true; }
}

export function setSoundEnabled(pageKey: string, enabled: boolean): void {
  try {
    const raw = localStorage.getItem(SOUND_PREF_KEY);
    const map = raw ? (JSON.parse(raw) as Record<string, boolean>) : {};
    map[pageKey] = enabled;
    localStorage.setItem(SOUND_PREF_KEY, JSON.stringify(map));
  } catch {}
}

const DEDUP_WINDOW_MS = 600;
const dedupMap = new Map<string, number>();

function isDuplicate(type: NotificationSoundType): boolean {
  const last = dedupMap.get(type);
  return !!last && Date.now() - last < DEDUP_WINDOW_MS;
}

function markPlayed(type: NotificationSoundType): void {
  dedupMap.set(type, Date.now());
}

function playTingWebAudio(volume: number): boolean {
  try {
    const ctx = getCtx();
    if (!ctx || ctx.state !== 'running') return false;
    const partials = [
      { freq: 1760, amp: 1.0 },
      { freq: 3136, amp: 0.55 },
      { freq: 4400, amp: 0.30 },
      { freq: 6000, amp: 0.15 },
    ];
    const master = ctx.createGain();
    master.gain.value = Math.min(1.0, volume * 1.4);
    master.connect(ctx.destination);
    const now = ctx.currentTime;
    const decayTime = 0.55;
    partials.forEach(({ freq, amp }) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0, now);
      gain.gain.linearRampToValueAtTime(amp, now + 0.002);
      gain.gain.exponentialRampToValueAtTime(0.001, now + decayTime);
      osc.connect(gain); gain.connect(master);
      osc.start(now); osc.stop(now + decayTime);
    });
    audioUnlocked = true;
    return true;
  } catch { return false; }
}

function generateTingWav(volume = 0.9, sampleRate = 22050): string {
  const durationMs = 550;
  const numSamples = Math.floor((sampleRate * durationMs) / 1000);
  const buffer = new ArrayBuffer(44 + numSamples * 2);
  const view = new DataView(buffer);
  const write = (offset: number, str: string) => {
    for (let i = 0; i < str.length; i++) view.setUint8(offset + i, str.charCodeAt(i));
  };
  write(0, 'RIFF'); view.setUint32(4, 36 + numSamples * 2, true); write(8, 'WAVE');
  write(12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true);
  view.setUint16(22, 1, true); view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true); view.setUint16(32, 2, true);
  view.setUint16(34, 16, true); write(36, 'data'); view.setUint32(40, numSamples * 2, true);
  const partials = [{ freq: 1760, amp: 1.0 }, { freq: 3136, amp: 0.55 }, { freq: 4400, amp: 0.30 }, { freq: 6000, amp: 0.15 }];
  for (let i = 0; i < numSamples; i++) {
    const t = i / sampleRate;
    const attack = Math.min(1, i / (sampleRate * 0.002));
    const decay = Math.exp(-t * 6.5);
    const env = attack * decay * volume;
    let sample = 0;
    for (const { freq, amp } of partials) sample += amp * Math.sin(2 * Math.PI * freq * t);
    const totalAmp = partials.reduce((s, p) => s + p.amp, 0);
    sample /= totalAmp;
    view.setInt16(44 + i * 2, Math.round(sample * env * 29000), true);
  }
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  return 'data:audio/wav;base64,' + btoa(binary);
}

function generateBeepWav(frequencies: number[], durationMs: number, sampleRate = 22050): string {
  const numSamples = Math.floor((sampleRate * durationMs) / 1000);
  const buffer = new ArrayBuffer(44 + numSamples * 2);
  const view = new DataView(buffer);
  const write = (offset: number, str: string) => {
    for (let i = 0; i < str.length; i++) view.setUint8(offset + i, str.charCodeAt(i));
  };
  write(0, 'RIFF'); view.setUint32(4, 36 + numSamples * 2, true); write(8, 'WAVE');
  write(12, 'fmt '); view.setUint32(16, 16, true); view.setUint16(20, 1, true);
  view.setUint16(22, 1, true); view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true); view.setUint16(32, 2, true);
  view.setUint16(34, 16, true); write(36, 'data'); view.setUint32(40, numSamples * 2, true);
  for (let i = 0; i < numSamples; i++) {
    const t = i / sampleRate;
    const attack = Math.min(1, i / (sampleRate * 0.01));
    const fade = Math.min(1, (numSamples - i) / (numSamples * 0.25));
    const env = attack * fade;
    let sample = 0;
    for (const f of frequencies) sample += Math.sin(2 * Math.PI * f * t) / frequencies.length;
    view.setInt16(44 + i * 2, Math.round(sample * env * 28000), true);
  }
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  return 'data:audio/wav;base64,' + btoa(binary);
}

let tingWavUrl: string | null = null;
const audioCache: Partial<Record<NotificationSoundType, string>> = {};

function getAudioDataUrl(type: NotificationSoundType): string {
  if (type === 'newOrder' || type === 'onlineOrderVoice') {
    if (!tingWavUrl) tingWavUrl = generateTingWav(0.95);
    return tingWavUrl;
  }
  if (!audioCache[type]) {
    switch (type) {
      case 'cashierOrder':  audioCache[type] = generateBeepWav([660, 880], 180); break;
      case 'success':       audioCache[type] = generateBeepWav([523, 659], 250); break;
      case 'statusChange':  audioCache[type] = generateBeepWav([440], 300); break;
      case 'alert':         audioCache[type] = generateBeepWav([880, 659], 300); break;
      default: (audioCache as Record<string, string>)[type] = generateBeepWav([523, 659, 784], 350);
    }
  }
  return audioCache[type]!;
}

async function playTingAudio(volume: number): Promise<void> {
  await ensureRunning();
  if (playTingWebAudio(volume)) return;
  try {
    const audio = new Audio(getAudioDataUrl('newOrder'));
    audio.volume = Math.min(1, volume);
    await audio.play();
    await new Promise<void>((resolve) => {
      audio.onended = () => resolve();
      audio.onerror = () => resolve();
      setTimeout(resolve, 700);
    });
  } catch {}
}

function playBeepWebAudio(type: NotificationSoundType, volume: number): boolean {
  try {
    const ctx = getCtx();
    if (!ctx || ctx.state !== 'running') return false;
    const freqMap: Record<string, number[]> = {
      cashierOrder: [660, 880], success: [523, 659], statusChange: [440], alert: [880, 659],
    };
    const freqs = freqMap[type] || [523, 659, 784];
    const master = ctx.createGain();
    master.gain.value = volume;
    master.connect(ctx.destination);
    freqs.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(master);
      osc.type = 'sine'; osc.frequency.value = freq;
      const start = ctx.currentTime + i * 0.12;
      gain.gain.setValueAtTime(0, start);
      gain.gain.linearRampToValueAtTime(1 / freqs.length, start + 0.01);
      gain.gain.exponentialRampToValueAtTime(0.001, start + 0.28);
      osc.start(start); osc.stop(start + 0.3);
    });
    audioUnlocked = true;
    return true;
  } catch { return false; }
}

async function playBeep(type: NotificationSoundType, volume: number): Promise<void> {
  await ensureRunning();
  if (playBeepWebAudio(type, volume)) return;
  try {
    const audio = new Audio(getAudioDataUrl(type));
    audio.volume = Math.max(0, Math.min(1, volume));
    await audio.play();
    await new Promise<void>((resolve) => {
      audio.onended = () => resolve();
      audio.onerror = () => resolve();
      setTimeout(resolve, 800);
    });
  } catch {}
}

export async function testSound(type: NotificationSoundType = 'success', volume = 0.8): Promise<boolean> {
  try {
    await initAudioUnlock();
    if (type === 'newOrder' || type === 'onlineOrderVoice') {
      await playTingAudio(volume);
      await new Promise(r => setTimeout(r, 350));
      await playTingAudio(volume);
    } else { await playBeep(type, volume); }
    return true;
  } catch { return false; }
}

export async function playNotificationSound(
  type: NotificationSoundType = 'newOrder',
  volume: number = 0.95
): Promise<void> {
  if (isDuplicate(type)) return;
  markPlayed(type);
  await ensureRunning();
  if (type === 'onlineOrderVoice' || type === 'newOrder') {
    await playTingAudio(volume);
    await new Promise(r => setTimeout(r, 320));
    await playTingAudio(volume);
    await new Promise(r => setTimeout(r, 320));
    await playTingAudio(volume * 0.85);
  } else if (type === 'cashierOrder') {
    await playBeep('cashierOrder', volume);
    await new Promise(r => setTimeout(r, 200));
    await playBeep('cashierOrder', volume * 0.8);
  } else { await playBeep(type, volume); }
}

const DB_NAME = "fuji-offline-db";
const DB_VERSION = 2;
const STORE_NAME = "offline-orders";
const MAX_RETRIES = 5;

function openDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(DB_NAME, DB_VERSION);
    req.onupgradeneeded = (e) => {
      const db = (e.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        const store = db.createObjectStore(STORE_NAME, { keyPath: "localId" });
        store.createIndex("status", "status", { unique: false });
      } else {
        const tx = (e.target as IDBOpenDBRequest).transaction!;
        const store = tx.objectStore(STORE_NAME);
        if (!store.indexNames.contains("retryCount")) {
          store.createIndex("retryCount", "retryCount", { unique: false });
        }
      }
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

export interface OfflineOrder {
  localId: string;
  orderData: any;
  status: "pending" | "syncing" | "synced" | "failed";
  createdAt: string;
  retryCount: number;
  lastRetryAt?: string;
  nextRetryAt?: string;
  error?: string;
}

const RETRY_DELAYS_MS = [30_000, 120_000, 600_000, 1_800_000, 7_200_000];

export async function queueOfflineOrder(orderData: any): Promise<string> {
  const db = await openDB();
  const localId = `offline-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
  const record: OfflineOrder = {
    localId,
    orderData: { ...orderData, offlineQueued: true },
    status: "pending",
    createdAt: new Date().toISOString(),
    retryCount: 0,
  };
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readwrite");
    const store = tx.objectStore(STORE_NAME);
    const req = store.add(record);
    req.onsuccess = () => resolve(localId);
    req.onerror = () => reject(req.error);
  });
}

export async function getPendingOrders(): Promise<OfflineOrder[]> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readonly");
    const store = tx.objectStore(STORE_NAME);
    const idx = store.index("status");
    const req = idx.getAll("pending");
    req.onsuccess = () => {
      const now = Date.now();
      const ready = (req.result as OfflineOrder[]).filter(o => {
        if (o.retryCount >= MAX_RETRIES) return false;
        if (!o.nextRetryAt) return true;
        return new Date(o.nextRetryAt).getTime() <= now;
      });
      resolve(ready);
    };
    req.onerror = () => reject(req.error);
  });
}

export async function getAllOfflineOrders(): Promise<OfflineOrder[]> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readonly");
    const store = tx.objectStore(STORE_NAME);
    const req = store.getAll();
    req.onsuccess = () => resolve((req.result as OfflineOrder[]).sort((a, b) => b.createdAt.localeCompare(a.createdAt)));
    req.onerror = () => reject(req.error);
  });
}

export async function updateOrderStatus(localId: string, status: OfflineOrder["status"], error?: string): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readwrite");
    const store = tx.objectStore(STORE_NAME);
    const getReq = store.get(localId);
    getReq.onsuccess = () => {
      const record = getReq.result as OfflineOrder | undefined;
      if (record) {
        record.status = status;
        if (error) record.error = error;
        if (status === "pending") {
          const newCount = (record.retryCount || 0) + 1;
          record.retryCount = newCount;
          record.lastRetryAt = new Date().toISOString();
          const delayMs = RETRY_DELAYS_MS[Math.min(newCount - 1, RETRY_DELAYS_MS.length - 1)];
          record.nextRetryAt = new Date(Date.now() + delayMs).toISOString();
          if (newCount >= MAX_RETRIES) {
            record.status = "failed";
            record.error = error || `فشل بعد ${MAX_RETRIES} محاولات`;
          }
        }
        store.put(record);
      }
      resolve();
    };
    getReq.onerror = () => reject(getReq.error);
  });
}

export async function clearSyncedOrders(): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readwrite");
    const store = tx.objectStore(STORE_NAME);
    const idx = store.index("status");
    const req = idx.getAll("synced");
    req.onsuccess = () => {
      const synced = req.result as OfflineOrder[];
      synced.forEach(o => store.delete(o.localId));
      resolve();
    };
    req.onerror = () => reject(req.error);
  });
}

export async function clearFailedOrders(): Promise<number> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readwrite");
    const store = tx.objectStore(STORE_NAME);
    const idx = store.index("status");
    const req = idx.getAll("failed");
    req.onsuccess = () => {
      const failed = req.result as OfflineOrder[];
      failed.forEach(o => store.delete(o.localId));
      resolve(failed.length);
    };
    req.onerror = () => reject(req.error);
  });
}

export async function retryFailedOrder(localId: string): Promise<void> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(STORE_NAME, "readwrite");
    const store = tx.objectStore(STORE_NAME);
    const getReq = store.get(localId);
    getReq.onsuccess = () => {
      const record = getReq.result as OfflineOrder | undefined;
      if (record) {
        record.status = "pending";
        record.retryCount = 0;
        record.error = undefined;
        record.nextRetryAt = undefined;
        store.put(record);
      }
      resolve();
    };
    getReq.onerror = () => reject(getReq.error);
  });
}

export async function syncOfflineOrders(): Promise<{ synced: number; failed: number }> {
  const pending = await getPendingOrders();
  let synced = 0, failed = 0;
  for (const order of pending) {
    await updateOrderStatus(order.localId, "syncing");
    try {
      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(order.orderData),
      });
      if (res.ok) {
        await updateOrderStatus(order.localId, "synced");
        synced++;
      } else {
        const err = await res.json().catch(() => ({ error: "فشل الخادم" }));
        if (res.status >= 400 && res.status < 500) {
          await updateOrderStatus(order.localId, "failed", err.error || `خطأ ${res.status}`);
        } else {
          await updateOrderStatus(order.localId, "pending", err.error || "فشل الخادم — سيعاد المحاولة");
        }
        failed++;
      }
    } catch (err: any) {
      await updateOrderStatus(order.localId, "pending", err.message);
      failed++;
    }
  }
  if (synced > 0) await clearSyncedOrders();
  return { synced, failed };
}

export async function countPendingOrders(): Promise<number> {
  const pending = await getPendingOrders();
  return pending.length;
}

