  "pos.plate_number": "رقم اللوحة",
};

function mockT(key: string, params?: Record<string, any>): string {
  let text = AR_TRANSLATIONS[key] || key;
  if (params) {
    Object.entries(params).forEach(([k, v]) => {
      text = text.replace(`{{${k}}}`, String(v ?? ""));
    });
  }
  return text;
}

const mockI18n = { language: "ar" as const };

export function useTranslation() {
  return {
    t: mockT,
    i18n: mockI18n,
  };
}

export function preRenderReceiptPng(_data: any): void {
  // no-op stub — PNG pre-rendering not implemented
}

