import { useToast } from "@/hooks/use-toast";
import { useTranslate } from "@/lib/useTranslate";

interface PosShiftBarProps {
  employee: any;
  branchId?: string;
}

function formatElapsed(startMs: number) {
  const diff = Math.floor((Date.now() - startMs) / 1000);
  const h = Math.floor(diff / 3600);
  const m = Math.floor((diff % 3600) / 60);
  const s = diff % 60;
  return h > 0
    ? `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`
    : `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
}

export function PosShiftBar({ employee, branchId }: PosShiftBarProps) {
  const tc = useTranslate();
  const { toast } = useToast();
  const [shiftStartMs] = useState(() => {
    const stored = sessionStorage.getItem("pos-shift-start");
    if (stored) return Number(stored);
    const now = Date.now();
    sessionStorage.setItem("pos-shift-start", String(now));
    return now;
  });
  const [elapsed, setElapsed] = useState(() => formatElapsed(shiftStartMs));
  const [showClose, setShowClose] = useState(false);
  const [closingBalance, setClosingBalance] = useState("");
  const [closing, setClosing] = useState(false);

  useEffect(() => {
    const t = setInterval(() => setElapsed(formatElapsed(shiftStartMs)), 1000);
    return () => clearInterval(t);
  }, [shiftStartMs]);

  const handleCloseShift = async () => {
    setClosing(true);
    try {
      await fetch("/api/pos/shift/close", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          branchId: branchId || employee?.branchId,
          employeeId: employee?.id,
          closingBalance: parseFloat(closingBalance) || 0,
        }),
        credentials: "include",
      });
      toast({ title: tc("تم إغلاق الوردية", "Shift closed"), className: "bg-green-600 text-white" });
      sessionStorage.removeItem("pos-shift-start");
      setShowClose(false);
    } catch {
      toast({ variant: "destructive", title: tc("خطأ", "Error"), description: tc("فشل إغلاق الوردية", "Failed to close shift") });
    } finally {
      setClosing(false);
    }
  };

  return (
    <>
      <div className="flex items-center gap-2 text-xs text-muted-foreground shrink-0">
        <div className="hidden sm:flex items-center gap-1.5 bg-muted/60 rounded-lg px-2.5 py-1.5 border border-border/50">
          <User className="w-3.5 h-3.5 text-primary" />
          <span className="font-bold text-foreground">{employee?.fullName || employee?.name || tc("الكاشير","Cashier")}</span>
        </div>
        <div className="flex items-center gap-1.5 bg-muted/60 rounded-lg px-2.5 py-1.5 border border-border/50">
          <Clock className="w-3.5 h-3.5 text-primary" />
          <span className="font-mono font-bold text-foreground" data-testid="text-shift-elapsed">{elapsed}</span>
        </div>
        <Button
          size="sm"
          variant="outline"
          className="h-7 text-[11px] gap-1 border-orange-300 text-orange-600 hover:bg-orange-50 dark:hover:bg-orange-950/30"
          onClick={() => setShowClose(true)}
          data-testid="button-close-shift"
        >
          <LogOut className="w-3 h-3" />
          <span className="hidden sm:inline">{tc("إغلاق الوردية", "Close Shift")}</span>
        </Button>
      </div>

      <Dialog open={showClose} onOpenChange={setShowClose}>
        <DialogContent className="max-w-sm" dir="rtl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <DollarSign className="w-5 h-5 text-primary" />
              {tc("إغلاق الوردية", "Close Shift")}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="bg-muted/40 rounded-xl p-3 space-y-1.5 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">{tc("الكاشير","Cashier")}</span>
                <span className="font-bold">{employee?.fullName || employee?.name || "—"}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">{tc("مدة الوردية","Shift duration")}</span>
                <span className="font-mono font-bold">{elapsed}</span>
              </div>
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs font-bold">{tc("الرصيد الختامي (نقدي)","Closing cash balance")}</Label>
              <div className="flex gap-2">
                <Input
                  type="number"
                  min={0}
                  step={0.5}
                  placeholder="0.00"
                  value={closingBalance}
                  onChange={(e) => setClosingBalance(e.target.value)}
                  className="text-base font-bold"
                  data-testid="input-closing-balance"
                />
                <span className="flex items-center text-sm font-bold text-muted-foreground">ر.س</span>
              </div>
            </div>
            <div className="flex gap-2 pt-1">
              <Button variant="outline" className="flex-1" onClick={() => setShowClose(false)}>
                {tc("إلغاء","Cancel")}
              </Button>
              <Button
                className="flex-1 gap-1.5"
                onClick={handleCloseShift}
                disabled={closing}
                data-testid="button-confirm-close-shift"
              >
                <CheckCircle className="w-4 h-4" />
                {closing ? tc("جاري الإغلاق...","Closing...") : tc("تأكيد الإغلاق","Confirm Close")}
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Plus, Minus, ShoppingCart, Check } from "lucide-react";
import SarIcon from "@/components/sar-icon";
import { useTranslate } from "@/lib/useTranslate";

export interface DrinkCustomization {
  selectedSize?: string | null;
  selectedItemAddons?: Array<{ nameAr: string; nameEn?: string; price: number }>;
}

interface DrinkCustomizationDialogProps {
  open: boolean;
  onClose: () => void;
  item: any;
  group?: any[];
  initialCustomization?: DrinkCustomization;
  onAdd: (customization: DrinkCustomization, size: string | null, quantity: number, fullCustomization?: DrinkCustomization) => void;
}

export default function DrinkCustomizationDialog({
  open,
  onClose,
  item,
  initialCustomization,
  onAdd,
}: DrinkCustomizationDialogProps) {
  const tc = useTranslate();
  const [quantity, setQuantity] = useState(1);
  const [selectedSize, setSelectedSize] = useState<string | null>(null);
  const [selectedAddons, setSelectedAddons] = useState<Array<{ nameAr: string; nameEn?: string; price: number }>>([]);

  useEffect(() => {
    if (open && item) {
      setQuantity(1);
      const initSize = initialCustomization?.selectedSize ?? (item.availableSizes?.[0]?.nameAr ?? null);
      setSelectedSize(initSize ?? null);
      setSelectedAddons(initialCustomization?.selectedItemAddons ?? []);
    }
  }, [open, item, initialCustomization]);

  if (!item) return null;

  const sizes: Array<{ nameAr: string; nameEn?: string; price: number | string }> = item.availableSizes || [];
  const addons: Array<{ id?: string; nameAr: string; nameEn?: string; price: number }> = item.addons || [];

  const currentSizePrice = (() => {
    if (selectedSize && sizes.length > 0) {
      const s = sizes.find((sz) => sz.nameAr === selectedSize);
      if (s) return Number(s.price) || 0;
    }
    return Number(item.price) || 0;
  })();

  const addonsTotal = selectedAddons.reduce((s, a) => s + (Number(a.price) || 0), 0);
  const unitPrice = currentSizePrice + addonsTotal;
  const totalPrice = unitPrice * quantity;

  const toggleAddon = (addon: { nameAr: string; nameEn?: string; price: number }) => {
    setSelectedAddons((prev) => {
      const exists = prev.some((a) => a.nameAr === addon.nameAr);
      if (exists) return prev.filter((a) => a.nameAr !== addon.nameAr);
      return [...prev, addon];
    });
  };

  const handleConfirm = () => {
    const customization: DrinkCustomization = {
      selectedSize: selectedSize ?? undefined,
      selectedItemAddons: selectedAddons,
    };
    onAdd(customization, selectedSize, quantity, customization);
    onClose();
  };

  return (
    <Dialog open={open} onOpenChange={(v) => { if (!v) onClose(); }}>
      <DialogContent className="max-w-md p-0 overflow-hidden" dir="rtl" data-testid="dialog-drink-customization">
        <DialogHeader className="px-5 pt-4 pb-3 border-b bg-gradient-to-l from-primary/5 to-transparent">
          <DialogTitle className="text-base font-black">
            {item.nameAr || item.name}
          </DialogTitle>
          {item.nameEn && (
            <p className="text-xs text-muted-foreground mt-0.5" dir="ltr">{item.nameEn}</p>
          )}
        </DialogHeader>

        <div className="p-4 space-y-4 max-h-[60vh] overflow-y-auto">
          {sizes.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-bold text-muted-foreground uppercase tracking-wide">
                {tc("اختر الحجم", "Choose Size")}
              </p>
              <div className="grid grid-cols-2 gap-2">
                {sizes.map((sz) => (
                  <button
                    key={sz.nameAr}
                    onClick={() => setSelectedSize(sz.nameAr)}
                    className={`flex items-center justify-between px-3 py-2.5 rounded-xl border-2 transition-all text-sm font-bold ${
                      selectedSize === sz.nameAr
                        ? "border-primary bg-primary/10 text-primary"
                        : "border-border hover:border-primary/50 hover:bg-muted/40"
                    }`}
                    data-testid={`button-size-${sz.nameAr}`}
                  >
                    <span>{sz.nameAr}</span>
                    <span className="flex items-center gap-0.5 text-xs">
                      {Number(sz.price).toFixed(2)} <SarIcon size={10} />
                    </span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {addons.length > 0 && (
            <div className="space-y-2">
              <p className="text-xs font-bold text-muted-foreground uppercase tracking-wide">
                {tc("إضافات اختيارية", "Optional Addons")}
              </p>
              <div className="space-y-1.5">
                {addons.map((addon) => {
                  const isSelected = selectedAddons.some((a) => a.nameAr === addon.nameAr);
                  return (
                    <button
                      key={addon.nameAr}
                      onClick={() => toggleAddon(addon)}
                      className={`w-full flex items-center justify-between px-3 py-2 rounded-xl border-2 transition-all text-sm ${
                        isSelected
                          ? "border-primary bg-primary/10 text-primary"
                          : "border-border hover:border-primary/50 hover:bg-muted/40"
                      }`}
                      data-testid={`button-addon-${addon.nameAr}`}
                    >
                      <div className="flex items-center gap-2">
                        <div className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${isSelected ? "border-primary bg-primary" : "border-muted-foreground"}`}>
                          {isSelected && <Check className="w-2.5 h-2.5 text-primary-foreground" />}
                        </div>
                        <span className="font-bold">{addon.nameAr}</span>
                        {addon.nameEn && <span className="text-muted-foreground text-xs" dir="ltr">{addon.nameEn}</span>}
                      </div>
                      <span className="flex items-center gap-0.5 text-xs text-primary font-bold">
                        +{Number(addon.price).toFixed(2)} <SarIcon size={10} />
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        <div className="p-4 border-t bg-muted/20 space-y-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Button
                size="icon"
                variant="outline"
                className="h-8 w-8 rounded-full border-2"
                onClick={() => setQuantity((q) => Math.max(1, q - 1))}
                data-testid="button-qty-minus"
              >
                <Minus className="w-3.5 h-3.5" />
              </Button>
              <span className="text-xl font-black w-8 text-center" data-testid="text-qty">{quantity}</span>
              <Button
                size="icon"
                variant="outline"
                className="h-8 w-8 rounded-full border-2"
                onClick={() => setQuantity((q) => q + 1)}
                data-testid="button-qty-plus"
              >
                <Plus className="w-3.5 h-3.5" />
              </Button>
            </div>
            <div className="text-right">
              <p className="text-[11px] text-muted-foreground">{tc("الإجمالي","Total")}</p>
              <p className="font-black text-lg text-primary flex items-center gap-1">
                {totalPrice.toFixed(2)} <SarIcon size={14} />
              </p>
            </div>
          </div>

          <Button
            className="w-full h-11 font-black gap-2 text-base"
            onClick={handleConfirm}
            data-testid="button-add-to-cart"
          >
            <ShoppingCart className="w-5 h-5" />
            {tc("إضافة للطلب", "Add to Order")}
            {quantity > 1 && <Badge variant="secondary" className="text-xs">×{quantity}</Badge>}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import SarIcon from "@/components/sar-icon";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { printRefundThermal } from "@/lib/print-utils";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  RotateCcw, Search, CheckCircle, Loader2, CreditCard, Banknote,
  Printer, ChevronRight, X, AlertTriangle,
} from "lucide-react";
import { format } from "date-fns";
import { ar } from "date-fns/locale";
import { useTranslate } from "@/lib/useTranslate";

interface RefundDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  branchId?: string;
  employeeId?: string;
  employeeName?: string;
  tenantId?: string;
}

type RefundPayMethod = "cash" | "card" | "split";

export default function RefundDialog({ open, onOpenChange, branchId, employeeId, employeeName }: RefundDialogProps) {
  const { toast } = useToast();
  const tc = useTranslate();
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [foundOrder, setFoundOrder] = useState<any>(null);
  const [searchError, setSearchError] = useState("");
  const [selectedItems, setSelectedItems] = useState<Record<string, boolean>>({});
  const [refundQtys, setRefundQtys] = useState<Record<string, number>>({});
  const [payMethod, setPayMethod] = useState<RefundPayMethod>("cash");
  const [cashAmount, setCashAmount] = useState("");
  const [cardAmount, setCardAmount] = useState("");
  const [reason, setReason] = useState("");

  const reset = () => {
    setStep(1); setSearchQuery(""); setFoundOrder(null); setSearchError("");
    setSelectedItems({}); setRefundQtys({}); setPayMethod("cash");
    setCashAmount(""); setCardAmount(""); setReason("");
  };
  const handleClose = () => { reset(); onOpenChange(false); };

  const handleSearch = async () => {
    const q = searchQuery.trim();
    if (!q) return;
    setIsSearching(true);
    setSearchError("");
    setFoundOrder(null);
    try {
      const num = q.replace(/^#/, "");
      const res = await fetch(`/api/orders/number/${num}`, { credentials: "include" });
      if (res.ok) {
        const data = await res.json();
        if (data && (data._id || data.id)) {
          setFoundOrder(data);
          const initSelected: Record<string, boolean> = {};
          const initQtys: Record<string, number> = {};
          (data.items || []).forEach((it: any, idx: number) => {
            const id = it.coffeeItemId || it.productId || String(idx);
            initSelected[id] = false;
            initQtys[id] = it.quantity || 1;
          });
          setSelectedItems(initSelected);
          setRefundQtys(initQtys);
        } else {
          setSearchError(tc("لم يتم العثور على الطلب", "Order not found"));
        }
      } else {
        setSearchError(tc("لم يتم العثور على الطلب", "Order not found"));
      }
    } catch {
      setSearchError(tc("خطأ في الاتصال", "Connection error"));
    } finally {
      setIsSearching(false);
    }
  };

  const selectedRefundItems = foundOrder
    ? (foundOrder.items || []).filter((_: any, idx: number) => {
        const id = foundOrder.items[idx].coffeeItemId || foundOrder.items[idx].productId || String(idx);
        return selectedItems[id];
      })
    : [];

  const refundTotal = selectedRefundItems.reduce((s: number, item: any, idx: number) => {
    const id = item.coffeeItemId || item.productId || String(idx);
    const qty = refundQtys[id] || item.quantity || 1;
    return s + (Number(item.price || item.unitPrice || 0) * qty);
  }, 0);

  const refundMutation = useMutation({
    mutationFn: async () => {
      const items = (foundOrder?.items || [])
        .filter((_: any, idx: number) => {
          const id = foundOrder.items[idx].coffeeItemId || foundOrder.items[idx].productId || String(idx);
          return selectedItems[id];
        })
        .map((item: any, idx: number) => {
          const id = item.coffeeItemId || item.productId || String(idx);
          return {
            coffeeItemId: item.coffeeItemId || item.productId,
            nameAr: item.nameAr || item.coffeeItem?.nameAr || item.name || "",
            quantity: refundQtys[id] || item.quantity,
            unitPrice: Number(item.price || item.unitPrice || 0),
            subtotal: Number(item.price || item.unitPrice || 0) * (refundQtys[id] || item.quantity),
          };
        });
      return apiRequest("POST", `/api/orders/${foundOrder._id || foundOrder.id}/refund`, {
        items,
        payMethod,
        cashAmount: payMethod === "split" ? parseFloat(cashAmount) || 0 : payMethod === "cash" ? refundTotal : 0,
        cardAmount: payMethod === "split" ? parseFloat(cardAmount) || 0 : payMethod === "card" ? refundTotal : 0,
        reason,
        totalRefund: refundTotal,
        branchId,
        employeeId,
        employeeName,
      });
    },
    onSuccess: async () => {
      try {
        await printRefundThermal({
          orderNumber: String(foundOrder.orderNumber || foundOrder.dailyNumber || "—"),
          items: selectedRefundItems.map((item: any, idx: number) => {
            const id = item.coffeeItemId || item.productId || String(idx);
            return {
              nameAr: item.nameAr || item.coffeeItem?.nameAr || item.name || "",
              quantity: refundQtys[id] || item.quantity,
              unitPrice: Number(item.price || item.unitPrice || 0),
              subtotal: Number(item.price || item.unitPrice || 0) * (refundQtys[id] || item.quantity),
            };
          }),
          totalRefund: refundTotal,
          payMethod,
          reason,
          employeeName: employeeName || tc("الكاشير","Cashier"),
          date: new Date().toISOString(),
        });
      } catch {}
      toast({ title: tc("✅ تم الاسترداد","✅ Refund processed"), className: "bg-green-600 text-white" });
      handleClose();
    },
    onError: () => {
      toast({ variant: "destructive", title: tc("خطأ في الاسترداد","Refund error"), description: tc("تعذر معالجة الاسترداد","Could not process refund") });
    },
  });

  return (
    <Dialog open={open} onOpenChange={(v) => { if (!v) handleClose(); }}>
      <DialogContent className="max-w-lg p-0 overflow-hidden" dir="rtl" data-testid="dialog-refund">
        <DialogHeader className="px-5 pt-4 pb-3 border-b bg-gradient-to-l from-red-50 to-transparent dark:from-red-950/30">
          <DialogTitle className="flex items-center gap-2 text-base text-red-700 dark:text-red-400">
            <RotateCcw className="w-5 h-5" />
            {tc("استرداد / إرجاع","Refund / Return")}
          </DialogTitle>
        </DialogHeader>

        <div className="max-h-[75vh] overflow-y-auto">
          {step === 1 && (
            <div className="p-5 space-y-4">
              <div className="space-y-1.5">
                <Label className="text-xs font-bold">{tc("رقم الفاتورة","Invoice Number")}</Label>
                <div className="flex gap-2">
                  <Input
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleSearch()}
                    placeholder={tc("مثال: 0042 أو #0042","e.g. 0042 or #0042")}
                    className="flex-1"
                    data-testid="input-refund-search"
                  />
                  <Button onClick={handleSearch} disabled={isSearching || !searchQuery.trim()} data-testid="button-refund-search">
                    {isSearching ? <Loader2 className="w-4 h-4 animate-spin" /> : <Search className="w-4 h-4" />}
                  </Button>
                </div>
                {searchError && (
                  <p className="text-xs text-red-500 flex items-center gap-1">
                    <AlertTriangle className="w-3.5 h-3.5" /> {searchError}
                  </p>
                )}
              </div>

              {foundOrder && (
                <div className="space-y-3">
                  <div className="bg-muted/40 rounded-xl p-3 text-sm space-y-1.5">
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">{tc("رقم الطلب","Order #")}</span>
                      <span className="font-mono font-bold">#{foundOrder.orderNumber || foundOrder.dailyNumber}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">{tc("التاريخ","Date")}</span>
                      <span>{foundOrder.createdAt ? format(new Date(foundOrder.createdAt), "dd/MM/yyyy HH:mm", { locale: ar }) : "—"}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">{tc("الإجمالي","Total")}</span>
                      <span className="font-bold flex items-center gap-1">{Number(foundOrder.totalAmount).toFixed(2)} <SarIcon size={10} /></span>
                    </div>
                  </div>

                  <div className="space-y-1.5">
                    <p className="text-xs font-bold">{tc("اختر الأصناف للاسترداد","Select items to refund")}</p>
                    <ScrollArea className="max-h-48">
                      <div className="space-y-1.5">
                        {(foundOrder.items || []).map((item: any, idx: number) => {
                          const id = item.coffeeItemId || item.productId || String(idx);
                          const name = item.nameAr || item.coffeeItem?.nameAr || item.name || "—";
                          const price = Number(item.price || item.unitPrice || 0);
                          const maxQty = item.quantity || 1;
                          const currentQty = refundQtys[id] || maxQty;
                          const isSelected = selectedItems[id] || false;
                          return (
                            <div
                              key={id}
                              className={`flex items-center gap-2 p-2 rounded-lg border-2 cursor-pointer transition-all ${isSelected ? "border-red-400 bg-red-50 dark:bg-red-950/20" : "border-border hover:border-red-200"}`}
                              onClick={() => setSelectedItems((prev) => ({ ...prev, [id]: !prev[id] }))}
                              data-testid={`item-refund-${idx}`}
                            >
                              <div className={`w-4 h-4 rounded border-2 flex items-center justify-center shrink-0 ${isSelected ? "border-red-500 bg-red-500" : "border-muted-foreground"}`}>
                                {isSelected && <X className="w-2.5 h-2.5 text-white" />}
                              </div>
                              <div className="flex-1 min-w-0">
                                <p className="text-xs font-bold truncate">{name}</p>
                                <p className="text-[10px] text-muted-foreground">{price.toFixed(2)} × {maxQty}</p>
                              </div>
                              {isSelected && maxQty > 1 && (
                                <div className="flex items-center gap-1" onClick={(e) => e.stopPropagation()}>
                                  <button
                                    className="w-5 h-5 rounded-full border text-xs flex items-center justify-center hover:bg-muted"
                                    onClick={() => setRefundQtys((p) => ({ ...p, [id]: Math.max(1, (p[id] || maxQty) - 1) }))}
                                  >−</button>
                                  <span className="text-xs font-bold w-4 text-center">{currentQty}</span>
                                  <button
                                    className="w-5 h-5 rounded-full border text-xs flex items-center justify-center hover:bg-muted"
                                    onClick={() => setRefundQtys((p) => ({ ...p, [id]: Math.min(maxQty, (p[id] || maxQty) + 1) }))}
                                  >+</button>
                                </div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </ScrollArea>
                  </div>

                  {refundTotal > 0 && (
                    <div className="bg-red-50 dark:bg-red-950/20 rounded-xl p-3 flex justify-between items-center border border-red-200 dark:border-red-900">
                      <span className="text-sm font-bold text-red-700">{tc("مبلغ الاسترداد","Refund amount")}</span>
                      <span className="font-black text-lg text-red-700 flex items-center gap-1">
                        {refundTotal.toFixed(2)} <SarIcon size={14} />
                      </span>
                    </div>
                  )}

                  <Button
                    className="w-full gap-1.5"
                    disabled={refundTotal <= 0}
                    onClick={() => setStep(2)}
                    data-testid="button-refund-next"
                  >
                    {tc("التالي — طريقة الاسترداد","Next — Refund method")}
                    <ChevronRight className="w-4 h-4" />
                  </Button>
                </div>
              )}
            </div>
          )}

          {step === 2 && (
            <div className="p-5 space-y-4">
              <div className="space-y-1.5">
                <p className="text-sm font-bold">{tc("طريقة الاسترداد","Refund method")}</p>
                <div className="grid grid-cols-3 gap-2">
                  {(["cash","card","split"] as RefundPayMethod[]).map((m) => (
                    <Button
                      key={m}
                      variant={payMethod === m ? "default" : "outline"}
                      size="sm"
                      className="flex-col gap-0.5 h-auto py-2"
                      onClick={() => setPayMethod(m)}
                      data-testid={`button-refund-method-${m}`}
                    >
                      {m === "cash" ? <Banknote className="w-4 h-4" /> : m === "card" ? <CreditCard className="w-4 h-4" /> : <span className="text-xs">نقدي+شبكة</span>}
                      <span className="text-[10px]">{m === "cash" ? tc("نقدي","Cash") : m === "card" ? tc("شبكة","Card") : tc("مختلط","Split")}</span>
                    </Button>
                  ))}
                </div>
              </div>

              {payMethod === "split" && (
                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <Label className="text-xs">{tc("نقدي","Cash")}</Label>
                    <Input type="number" min={0} step={0.5} value={cashAmount} onChange={(e) => setCashAmount(e.target.value)} data-testid="input-refund-cash" />
                  </div>
                  <div className="space-y-1">
                    <Label className="text-xs">{tc("شبكة","Card")}</Label>
                    <Input type="number" min={0} step={0.5} value={cardAmount} onChange={(e) => setCardAmount(e.target.value)} data-testid="input-refund-card" />
                  </div>
                </div>
              )}

              <div className="space-y-1.5">
                <Label className="text-xs font-bold">{tc("سبب الاسترداد","Reason")}</Label>
                <Input value={reason} onChange={(e) => setReason(e.target.value)} placeholder={tc("اختياري — العيب، طلب خاطئ...","Optional — Defect, wrong order...")} data-testid="input-refund-reason" />
              </div>

              <Separator />
              <div className="flex items-center justify-between text-sm font-bold">
                <span>{tc("إجمالي الاسترداد","Total refund")}</span>
                <span className="text-red-600 flex items-center gap-1 text-base">
                  {refundTotal.toFixed(2)} <SarIcon size={13} />
                </span>
              </div>

              <div className="flex gap-2">
                <Button variant="outline" className="flex-1" onClick={() => setStep(1)}>{tc("رجوع","Back")}</Button>
                <Button
                  className="flex-1 gap-1.5 bg-red-600 hover:bg-red-700"
                  onClick={() => refundMutation.mutate()}
                  disabled={refundMutation.isPending}
                  data-testid="button-confirm-refund"
                >
                  {refundMutation.isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : <><Printer className="w-4 h-4" />{tc("تأكيد الاسترداد","Confirm Refund")}</>}
                </Button>
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

